   198→  @Get('status/:auditId')
   199→  @UseGuards(JwtAuthGuard)
   200→  @ApiOperation({ summary: 'Get enrichment audit status (updated from transaction compatibility)' })
   201→  @ApiParam({ name: 'auditId', description: 'Audit ID to check (replaces transaction ID)' })
   202→  @ApiResponse({
   203→    status: 200,
   204→    description: 'Audit status retrieved successfully'
